import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonNull()).thenReturn(true);
    // Cast to JsonNull for the test - create a JsonNull mock that extends JsonElement
    JsonNull jsonNull = mock(JsonNull.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    // Use spy to override isJsonNull to true and simulate getAsJsonNull
    JsonElement spyElement = spy(jsonNull);
    doReturn(true).when(spyElement).isJsonNull();

    JsonNull result = spyElement.getAsJsonNull();

    assertSame(spyElement, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonNull()).thenReturn(false);
    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonNull);
    assertTrue(exception.getMessage().startsWith("Not a JSON Null: "));
  }
}
